def is_prime(n):
    if n < 2:
        return False
    for i in range(2, int(n**0.5) + 1):
        if n % i == 0:
            return False
    return True

def find_max(lst):
    if not lst:
        return None
    return max(lst)

def is_palindrome(s):
    s = s.lower().replace(' ', '')
    return s == s[::-1]
